fn:get_phrases_from_posmap(posmaps:BoolTensor, input_ids:LongTensor)->List[List[int]] = {
  left,right = 0,posmaps.shape[-1]-1
  posmaps = posmaps.clone() |> λp: p[:,0:left+1]=False & p[:,right:] = False
  [list(input_ids[i] for i in p.nonzero(as_tuple=True)[0].tolist()) for p in posmaps]
}
